        function renderProducts(products, container) {
            const html = products.map(product => `
                <div class="product-card" onclick="openProductModal(${product.id})">
                    <div class="product-image">
                        ${product.emoji}
                        ${product.badge ? `<div class="product-badge badge-${product.badge}">${product.badge === 'retro' ? 'RETRO' : product.badge === 'new' ? 'NEW' : 'ULTIMI PEZZI'}</div>` : ''}
                    </div>
                    <div class="product-info">
                        <div class="product-name">${product.name}</div>
                        <div class="product-season">${product.season}</div>
                        <div class="product-rating">${product.rating}</div>
                        <div class="product-footer">
                            <div class="product-price">€${product.price.toFixed(2)}</div>
                            <div class="product-actions">
                                <button class="icon-btn" onclick="event.stopPropagation(); addToCart(${product.id})">🛒</button>
                                <button class="icon-btn" onclick="event.stopPropagation();">♡</button>
                            </div>
                        </div>
                    </div>
                </div>
            `).join('');
            container.innerHTML = html;
        }

